// Strict mode validation + image extraction
const item = $input.first();
const product = item.json;

const errors = [];
if (!product.name || String(product.name).trim() === '') errors.push('Product name is missing');
if (!product.price || String(product.price).trim() === '') errors.push('Product price is missing');
if (!product.permalink || String(product.permalink).trim() === '') errors.push('Product permalink is missing');

let imageUrls = [];
if (Array.isArray(product.images) && product.images.length > 0) {
  imageUrls = product.images
    .map(img => (typeof img === 'string' ? img : img?.src))
    .filter(url => url && typeof url === 'string' && url.startsWith('http'))
    .slice(0, 10);
}

const categoryNames = Array.isArray(product.categories)
  ? product.categories.map(c => c.name || c).filter(Boolean).join(', ')
  : '';
const tagNames = Array.isArray(product.tags)
  ? product.tags.map(t => t.name || t).filter(Boolean).join(', ')
  : '';

const stripHtml = (html) => String(html || '')
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const cleanDescription = stripHtml(product.description).slice(0, 1500);
const cleanShortDescription = stripHtml(product.short_description).slice(0, 300);

return [{
  json: {
    ...product,
    image_urls: imageUrls,
    primary_image: imageUrls[0] || null,
    has_images: imageUrls.length > 0,
    category_names: categoryNames,
    tag_names: tagNames,
    clean_description: cleanDescription,
    clean_short_description: cleanShortDescription,
    validation_errors: errors,
    is_valid: errors.length === 0 && imageUrls.length > 0
  }
}];

