parameters.jsCode:
// Detect duplicate based on Sheets lookup result
const input = $input.first();
const product = $('Set: Normalize Product Data').first().json;

const lookupResults = input.json || {};
const matchedRows = [];
for (const key of Object.keys(lookupResults)) {
  const v = lookupResults[key];
  if (Array.isArray(v) && v.length > 0) {
    matchedRows.push(...v);
  }
}

const alreadyPosted = matchedRows.some(r => r && r.Status === 'PUBLISHED');

return [{
  json: {
    ...product,
    duplicate: alreadyPosted,
    duplicate_match_count: matchedRows.length
  }
}];

// Build the OpenAI prompt from product data
const p = $input.first().json;

const productContext = `
Product Name: ${p.name}
Price: ${p.price}
Short Description: ${p.clean_short_description || (p.clean_description || '').slice(0, 200) || 'N/A'}
Description: ${p.clean_description || 'N/A'}
Categories: ${p.category_names || 'N/A'}
Tags: ${p.tag_names || 'N/A'}
Product URL: ${p.permalink}
`.trim();

const systemPrompt = `You are a social media copywriter for an e-commerce brand. Your job is to turn product information into scroll-stopping Instagram and Facebook posts.

RULES:
- Write a caption between 80 and 180 words. Punchy, sensory, conversational — not corporate.
- Front-load the hook in the first line so it works as the preview text before "...more".
- Use 2-4 short sentences max per caption. Emojis are OK, sparingly (1-3 total).
- Always include a clear call-to-action pointing to the product link.
- Generate between 8 and 15 hashtags. Mix broad (#style, #fashion) with niche (#productcategory). Put hashtags on a new line at the end.
- For Instagram: keep caption under 2200 chars. Hashtags go after the caption on a new line.
- For Facebook: lead with a value-driven hook, hashtags optional but include 2-3 if natural.
- Never invent product details that aren't in the input. If something is missing, lean on the description.
- Maintain a friendly, premium, modern brand voice.

Return a strict JSON object with exactly these keys: "instagram_caption", "facebook_caption", "hashtags" (array of strings without the leading #), "reasoning" (1 sentence explaining the angle).
No prose outside the JSON. No markdown fences.`;

const userPrompt = `Generate the social post for this product.\n\n${productContext}\n\nReturn strict JSON only.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    product_name: p.name,
    product_id: p.product_id,
    image_urls: p.image_urls,
    primary_image: p.primary_image,
    has_images: p.has_images,
    permalink: p.permalink,
    price: p.price
  }
}];

// Parse the OpenAI response
const item = $input.first();
const meta = $('Code: Build AI Prompt').first().json;

let raw = '';
if (item.json?.message?.content) {
  raw = item.json.message.content;
} else if (item.json?.choices?.[0]?.message?.content) {
  raw = item.json.choices[0].message.content;
} else if (typeof item.json?.output === 'string') {
  raw = item.json.output;
} else if (item.json?.error) {
  return [{
    json: {
      ...meta,
      caption_success: false,
      error: item.json.error?.message || 'OpenAI call failed',
      fallback_used: false
    }
  }];
}

let parsed = null;
const tryParse = (s) => { try { return JSON.parse(s); } catch (e) { return null; } };

parsed = tryParse(raw);
if (!parsed) {
  const stripped = raw.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
  parsed = tryParse(stripped);
}

if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      ...meta,
      caption_success: false,
      error: 'OpenAI did not return valid JSON',
      raw_response: String(raw).slice(0, 500),
      fallback_used: false
    }
  }];
}

const ig = String(parsed.instagram_caption || '').trim();
const fb = String(parsed.facebook_caption || '').trim();
const tags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];

if (!ig || !fb) {
  return [{
    json: {
      ...meta,
      caption_success: false,
      error: 'Caption missing in OpenAI response',
      fallback_used: false
    }
  }];
}

return [{
  json: {
    ...meta,
    caption_success: true,
    instagram_caption: ig,
    facebook_caption: fb,
    hashtags: tags,
    ai_reasoning: parsed.reasoning || '',
    raw_response: String(raw).slice(0, 1000)
  }
}];

// Fallback template when AI caption generation fails
const p = $('Set: Normalize Product Data').first().json;
const desc = (p.clean_short_description || p.clean_description || '').slice(0, 200);

const hashtags = [];
if (p.category_names) {
  p.category_names.split(',').slice(0, 3).forEach(c => {
    const tag = c.trim().toLowerCase().replace(/\s+/g, '');
    if (tag) hashtags.push(tag);
  });
}
hashtags.push('newproduct', 'shopnow', 'musthave');

const igCaption = `✨ New drop: ${p.name} \n\n${desc} \n\nShop now 👉 ${p.permalink}`;
const fbCaption = `New on the shop: ${p.name} — ${p.price} \n\n${desc} \n\nGet it here: ${p.permalink}`;

return [{
  json: {
    ...p,
    instagram_caption: igCaption,
    facebook_caption: fbCaption,
    hashtags: hashtags.slice(0, 10),
    ai_reasoning: 'Fallback template — OpenAI generation failed',
    caption_success: true,
    fallback_used: true
  }
}];

// Final post formatting — combine caption + hashtags + URL
const item = $input.first().json;

const tagList = (item.hashtags || [])
  .filter(t => t && typeof t === 'string')
  .map(t => t.replace(/^#/, '').trim())
  .filter(Boolean);

const hashtagString = tagList.length > 0
  ? '\n\n' + tagList.map(t => '#' + t).join(' ')
  : '';

let igFinal = (item.instagram_caption || '').trim() + hashtagString;
if (igFinal.length > 2200) {
  igFinal = igFinal.slice(0, 2197) + '...';
}

const fbHashtags = tagList.slice(0, 3).map(t => '#' + t).join(' ');
let fbFinal = (item.facebook_caption || '').trim();
if (fbHashtags) {
  fbFinal += '\n\n' + fbHashtags;
}

return [{
  json: {
    ...item,
    instagram_post_text: igFinal,
    facebook_post_text: fbFinal,
    hashtag_count: tagList.length,
    ready_to_publish: true
  }
}];

