parameters.jsCode:
// Code: Prepare Carousel Data
const item = $input.first().json;
const images = Array.isArray(item.image_urls) ? item.image_urls : [];
const isCarousel = images.length > 1;

return [{
  json: {
    product_id: item.product_id,
    product_name: item.name,
    permalink: item.permalink,
    price: item.price,
    caption: item.instagram_post_text,
    image_urls: images,
    is_carousel: isCarousel,
    image_count: images.length,
    fb_caption: item.facebook_post_text,
    fb_primary_image: images[0] || null,
    ai_reasoning: item.ai_reasoning || '',
    fallback_used: item.fallback_used || false
  }
}];

// Create Instagram Carousel via Graph API
// 1) child containers per image, 2) carousel container, 3) poll for FINISHED, 4) publish

const item = $input.first().json;
const IG_USER_ID = $env.IG_USER_ID;
const IG_ACCESS_TOKEN = $env.IG_ACCESS_TOKEN;
const API_VERSION = $env.GRAPH_API_VERSION || 'v22.0';

if (!IG_USER_ID || !IG_ACCESS_TOKEN) {
  throw new Error('IG_USER_ID and IG_ACCESS_TOKEN env vars are required');
}

const images = item.image_urls || [];
if (images.length === 0) {
  throw new Error('No images provided to publish to Instagram');
}

const baseUrl = `https://graph.facebook.com/${API_VERSION}/${IG_USER_ID}`;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Step 1: Create child containers
const childIds = [];
for (const imageUrl of images) {
  const body = images.length > 1
    ? { image_url: imageUrl, is_carousel_item: true, access_token: IG_ACCESS_TOKEN }
    : { image_url: imageUrl, caption: item.caption, access_token: IG_ACCESS_TOKEN };

  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/media`,
    body,
    json: true,
    timeout: 30000
  });
  if (!resp.id) {
    throw new Error(`Failed to create IG child container: ${JSON.stringify(resp)}`);
  }
  childIds.push(resp.id);
}

// Step 2: Create carousel container (if multiple images)
let creationId;
if (images.length > 1) {
  const carouselResp = await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/media`,
    body: {
      media_type: 'CAROUSEL',
      caption: item.caption,
      children: childIds,
      access_token: IG_ACCESS_TOKEN
    },
    json: true,
    timeout: 30000
  });
  if (!carouselResp.id) {
    throw new Error(`Failed to create IG carousel container: ${JSON.stringify(carouselResp)}`);
  }
  creationId = carouselResp.id;
} else {
  creationId = childIds[0];
}

// Step 3: Poll for FINISHED status (required for non-cached media)
let status = 'IN_PROGRESS';
let attempts = 0;
const maxAttempts = 12;
while (attempts < maxAttempts) {
  await sleep(5000);
  const statusResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://graph.facebook.com/${API_VERSION}/${creationId}`,
    qs: { fields: 'status_code,status', access_token: IG_ACCESS_TOKEN },
    json: true,
    timeout: 15000
  });
  status = statusResp.status_code || 'IN_PROGRESS';
  if (status === 'FINISHED') break;
  if (status === 'ERROR') {
    throw new Error(`IG container entered ERROR state: ${JSON.stringify(statusResp)}`);
  }
  attempts++;
}

if (status !== 'FINISHED') {
  throw new Error(`IG container not ready after ${maxAttempts} attempts. Last status: ${status}`);
}

// Step 4: Publish
const publishResp = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/media_publish`,
  body: { creation_id: creationId, access_token: IG_ACCESS_TOKEN },
  json: true,
  timeout: 30000
});

if (!publishResp.id) {
  throw new Error(`IG publish failed: ${JSON.stringify(publishResp)}`);
}

return [{
  json: {
    ...item,
    ig_creation_id: creationId,
    ig_post_id: publishResp.id,
    ig_status: 'PUBLISHED',
    ig_post_type: images.length > 1 ? 'CAROUSEL' : 'IMAGE',
    ig_image_count: images.length
  }
}];

// Build success log entry
const ig = $('Code: Create + Publish IG Carousel').first().json;
const fb = $input.first().json;

const igOk = ig?.ig_status === 'PUBLISHED';
const fbOk = !!fb?.id || !!fb?.post_id || (fb?.json && fb.json.id);

let overallStatus = 'PUBLISHED';
if (igOk && fbOk) overallStatus = 'PUBLISHED';
else if (igOk && !fbOk) overallStatus = 'PARTIAL_SUCCESS';
else overallStatus = 'FAILED';

const fbPostId = fb?.id || fb?.post_id || (fb?.json && fb.json.id) || '';
const fbError = fb?.error?.message || (fb?.json && fb.json.error?.message) || '';

return [{
  json: {
    product_id: ig.product_id || $('Set: Normalize Product Data').first().json.product_id,
    product_name: ig.product_name,
    platform: 'Instagram+Facebook',
    status: overallStatus,
    details: `IG: ${igOk ? 'OK' : 'FAIL'} (${ig.ig_post_type || 'IMAGE'}), FB: ${fbOk ? 'OK' : 'FAIL'}`,
    post_id: ig.ig_post_id || '',
    ig_post_id: ig.ig_post_id || '',
    fb_post_id: fbPostId,
    error: fbError,
    ig_type: ig.ig_post_type,
    ig_image_count: ig.ig_image_count,
    fallback_used: ig.fallback_used || false
  }
}];

